('chunk_0ea6ba7535ab31e261','file_162fce15bbe62004d5','geography.md','Where this subject sits','Geography in the IISH MYP belongs to the **Individuals and Societies (I&S)** subject group. I&S encourages students to study human and physical environments, and to appreciate that people, places, resources and societies are deeply connected. Grade 7 Geography focuses on **environmental regions and societies, resources and the environment, and the policy and governance of development.**','{"where":1,"this":1,"subject":2,"sits":1,"geography":2,"the":4,"iish":1,"myp":1,"belongs":1,"individuals":1,"and":8,"societies":3,"group":1,"encourages":1,"students":1,"study":1,"human":1,"physical":1,"environments":1,"appreciate":1,"that":1,"people":1,"places":1,"resources":2,"are":1,"deeply":1,"connected":1,"grade":1,"focuses":1,"environmental":1,"regions":1,"environment":1,"policy":1,"governance":1,"development":1}'::jsonb);